			runner := &fakeAgentRunner{result: &agent.Result{ExitCode: 0}}
			f := newExecuteBeadFactory(t, git, runner)

			root := f.NewRootCommand()
			_, cmdErr := executeCommand(root, "agent", "execute-bead", id)
			require.Error(t, cmdErr)
